import { Brouther, Outlet } from "brouther";
import { Maximize2 } from "lucide-react";
import { StrictMode, useEffect } from "react";
import { repositories, useGlobalStore } from "../store/global.store";
import { Note } from "../store/note";
import { SettingsRepository } from "../store/settings";
import { useUIStore } from "../store/ui.store";
import { Commander } from "./commander";
import { DirectoryBrowserDialog } from "./components/directory-browser-dialog";
import { OpenProjectDialog } from "./components/open-project-dialog";
import { Sidebar } from "./components/sidebar";
import { PWAInstallButton } from "./elements/pwa-install-button";
import { Footer } from "./footer";
import { Navbar } from "./navbar";
import { router } from "./router";
import { ShortcutsCommands } from "./tutorial/shortcuts-commands";

export const App = () => {
  const [state, dispatch] = useGlobalStore();
  const [uiState, uiDispatch] = useUIStore();

  // Session restoration (IndexedDB-first: always restore, use default project as fallback)
  useEffect(() => {
    const restoreSession = async () => {
      const settings = SettingsRepository.load();
      // Use storageDirectory if configured, otherwise use default project for IndexedDB-only mode
      const project = settings.storageDirectory || Note.DEFAULT_PROJECT;

      // Load tabs for current project
      await dispatch.loadTabs(project);

      // If there's an active tab, ensure its note is loaded
      if (state.activeTabId) {
        const tabs = await repositories.tabs.getAll(project);
        const activeTab = tabs.find((t) => t.id === state.activeTabId);
        if (activeTab) {
          const note = await repositories.notes.getOne(activeTab.noteId);
          if (note) {
            dispatch.setNote(note);
          }
        }
      }
    };
    restoreSession();
  }, []);

  // Focus mode keyboard shortcut: Cmd/Ctrl + Shift + F
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.shiftKey && e.key === "f") {
        e.preventDefault();
        uiDispatch.toggleFocusMode();
      }
    };

    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [uiDispatch]);

  return (
    <StrictMode>
      <Brouther config={router.config}>
        <div className="flex flex-col flex-1 justify-center items-center isolate">
          <Commander />
          <Navbar />
          <div className="w-full flex flex-1 min-h-0">
            {!uiState.focusMode && (
              <div className="hidden lg:block">
                <Sidebar />
              </div>
            )}
            <div className="flex flex-col flex-1 min-w-0">
              <ShortcutsCommands />
              <DirectoryBrowserDialog />
              <OpenProjectDialog />
              <Outlet />
            </div>
          </div>
          <PWAInstallButton />
          {uiState.focusMode && (
            <button
              title="Exit focus mode (⌘⇧F)"
              onClick={() => uiDispatch.toggleFocusMode()}
              className="flex fixed right-6 bottom-6 z-50 gap-2 items-center py-2 px-4 text-sm rounded-lg border shadow-lg transition-all hover:scale-105 bg-background/80 border-border backdrop-blur-md text-foreground/70 animate-fade-in hover:text-foreground"
            >
              <Maximize2 className="size-4" />
              <span>Exit Focus</span>
            </button>
          )}
          <Footer />
        </div>
      </Brouther>
    </StrictMode>
  );
};
